function removeCardFromColumn(column, cardId) {
  const newCards = column.cards.filter(c => c.id !== cardId);
  const newCardOrderIds = newCards.map(c => c.id);
  return { ...column, cards: newCards, cardOrderIds: newCardOrderIds };
}

