function moveCardBetweenColumns(oldColumn, newColumn, activeCard, newCardIndex) {
  // Cập nhật cột cũ
  const updatedOldColumnCards = oldColumn.cards.filter(c => c.id !== activeCard.id);
  const finalOldColumn = { 
    ...oldColumn, 
    cards: updatedOldColumnCards, 
    cardOrderIds: updatedOldColumnCards.map(c => c.id) 
  };

  // Cập nhật cột mới
  const updatedNewColumnCards = newColumn.cards.toSpliced(newCardIndex, 0, activeCard);
  const finalNewColumn = { 
    ...newColumn, 
    cards: updatedNewColumnCards, 
    cardOrderIds: updatedNewColumnCards.map(c => c.id) 
  };

  return [finalOldColumn, finalNewColumn];
}

