codeExercises.solution:
function handleMoveDifferentColumn(orderedColumns, active, over) {
  const { id: activeDraggingCardId, data: { current: { columnId: oldColumnId } } } = active;
  const { id: overCardId, data: { current: { columnId: newColumnId } } } = over;

  const oldColumn = orderedColumns.find(c => c.id === oldColumnId);
  const newColumn = orderedColumns.find(c => c.id === newColumnId);

  if (!oldColumn || !newColumn || !active.data.current.card) return orderedColumns;

  const activeDraggingCard = active.data.current.card;
  let newCardIndex;
  if (over.id in newColumn.cards.map(c=>c.id)) {
    newCardIndex = newColumn.cards.findIndex(c => c.id === overCardId);
  } else {
    newCardIndex = newColumn.cards.length;
  }

  const newOrderedColumns = orderedColumns.map(column => {
    if (column.id === oldColumn.id) {
      const newCards = oldColumn.cards.filter(c => c.id !== activeDraggingCardId);
      return { ...column, cards: newCards, cardOrderIds: newCards.map(c => c.id) };
    }
    if (column.id === newColumn.id) {
      const newCards = newColumn.cards.toSpliced(newCardIndex, 0, activeDraggingCard);
      return { ...column, cards: newCards, cardOrderIds: newCards.map(c => c.id) };
    }
    return column;
  });

  return newOrderedColumns;
}
